using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Helpers;

internal static class TestDbContextFactory
{
    public static SchoolContext Create(string? dbName = null)
    {
        dbName ??= Guid.NewGuid().ToString();
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName)
            .Options;

        var context = new SchoolContext(options);
        context.Database.EnsureCreated();
        return context;
    }

    public static SchoolContext CreateSeeded(string? dbName = null)
    {
        var context = Create(dbName);
        SeedData(context);
        return context;
    }

    private static void SeedData(SchoolContext context)
    {
        var instructors = new[]
        {
            new Instructor { ID = 1, LastName = "Abercrombie", FirstMidName = "Kim", HireDate = DateTime.Parse("1995-03-11") },
            new Instructor { ID = 2, LastName = "Fakhouri", FirstMidName = "Fadi", HireDate = DateTime.Parse("2002-07-06") },
            new Instructor { ID = 3, LastName = "Harui", FirstMidName = "Roger", HireDate = DateTime.Parse("1998-07-01") },
        };
        context.Instructors.AddRange(instructors);

        var departments = new[]
        {
            new Department { DepartmentID = 1, Name = "English", Budget = 350000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 1 },
            new Department { DepartmentID = 2, Name = "Mathematics", Budget = 100000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 2 },
            new Department { DepartmentID = 3, Name = "Engineering", Budget = 350000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 3 },
        };
        context.Departments.AddRange(departments);

        var courses = new[]
        {
            new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 3 },
            new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 1 },
            new Course { CourseID = 4041, Title = "Macroeconomics", Credits = 3, DepartmentID = 1 },
        };
        context.Courses.AddRange(courses);

        var students = new[]
        {
            new Student { ID = 10, LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = DateTime.Parse("2010-09-01") },
            new Student { ID = 11, LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = DateTime.Parse("2012-09-01") },
            new Student { ID = 12, LastName = "Anand", FirstMidName = "Arturo", EnrollmentDate = DateTime.Parse("2013-09-01") },
            new Student { ID = 13, LastName = "Barzdukas", FirstMidName = "Gytis", EnrollmentDate = DateTime.Parse("2012-09-01") },
        };
        context.Students.AddRange(students);

        var enrollments = new[]
        {
            new Enrollment { EnrollmentID = 1, StudentID = 10, CourseID = 1050, Grade = Grade.A },
            new Enrollment { EnrollmentID = 2, StudentID = 10, CourseID = 4022, Grade = Grade.C },
            new Enrollment { EnrollmentID = 3, StudentID = 11, CourseID = 4041, Grade = Grade.B },
        };
        context.Enrollments.AddRange(enrollments);

        context.SaveChanges();
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests.Services;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new NotificationService();
        // Drain any leftover notifications from static queue
        while (_sut.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        _sut.Dispose();
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_EnqueuesNotification()
    {
        // Act
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("Admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
        Assert.IsTrue(notification.Message.Contains("John Doe"));
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesEntityIdInMessage()
    {
        // Act
        _sut.SendNotification("Course", "42", EntityOperation.UPDATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains("ID: 42"));
    }

    [TestMethod]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        // Act
        _sut.SendNotification("Department", "5", EntityOperation.DELETE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    [DataRow(EntityOperation.CREATE, "has been created")]
    [DataRow(EntityOperation.UPDATE, "has been updated")]
    [DataRow(EntityOperation.DELETE, "has been deleted")]
    public void SendNotification_GeneratesCorrectMessage(EntityOperation operation, string expectedFragment)
    {
        // Act
        _sut.SendNotification("Student", "1", "Test Student", operation, "User");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains(expectedFragment),
            $"Expected message to contain '{expectedFragment}', got: '{notification.Message}'");
    }

    [TestMethod]
    public void ReceiveNotification_WhenEmpty_ReturnsNull()
    {
        // Act
        var result = _sut.ReceiveNotification();

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void ReceiveNotification_ReturnsInFifoOrder()
    {
        // Arrange
        _sut.SendNotification("A", "1", EntityOperation.CREATE);
        _sut.SendNotification("B", "2", EntityOperation.UPDATE);
        _sut.SendNotification("C", "3", EntityOperation.DELETE);

        // Act & Assert
        Assert.AreEqual("A", _sut.ReceiveNotification()!.EntityType);
        Assert.AreEqual("B", _sut.ReceiveNotification()!.EntityType);
        Assert.AreEqual("C", _sut.ReceiveNotification()!.EntityType);
        Assert.IsNull(_sut.ReceiveNotification());
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // Act - should not throw (no-op implementation)
        _sut.MarkAsRead(999);
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAtToCurrentTime()
    {
        // Arrange
        var before = DateTime.Now;

        // Act
        _sut.SendNotification("Test", "1", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.CreatedAt >= before);
        Assert.IsTrue(notification.CreatedAt <= DateTime.Now);
    }
}

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Create_FirstPage_ReturnsCorrectItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 5);

        // Assert
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(5, result[4]);
    }

    [TestMethod]
    public void Create_SecondPage_SkipsFirstPageItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 2, pageSize: 5);

        // Assert
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(6, result[0]);
        Assert.AreEqual(10, result[4]);
    }

    [TestMethod]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 12).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 3, pageSize: 5);

        // Assert
        Assert.AreEqual(2, result.Count);
        Assert.AreEqual(11, result[0]);
        Assert.AreEqual(12, result[1]);
    }

    [TestMethod]
    public void TotalPages_CalculatedCorrectly()
    {
        // Arrange
        var source = Enumerable.Range(1, 12).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 5);

        // Assert
        Assert.AreEqual(3, result.TotalPages); // ceil(12/5) = 3
    }

    [TestMethod]
    public void TotalPages_ExactDivision_NoExtraPage()
    {
        // Arrange
        var source = Enumerable.Range(1, 10).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 5);

        // Assert
        Assert.AreEqual(2, result.TotalPages);
    }

    [TestMethod]
    public void HasPreviousPage_OnFirstPage_ReturnsFalse()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 5);

        // Assert
        Assert.IsFalse(result.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_OnSecondPage_ReturnsTrue()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 2, pageSize: 5);

        // Assert
        Assert.IsTrue(result.HasPreviousPage);
    }

    [TestMethod]
    public void HasNextPage_OnLastPage_ReturnsFalse()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 4, pageSize: 5);

        // Assert
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_OnFirstPage_ReturnsTrue()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 5);

        // Assert
        Assert.IsTrue(result.HasNextPage);
    }

    [TestMethod]
    public void PageIndex_StoresCorrectValue()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 3, pageSize: 5);

        // Assert
        Assert.AreEqual(3, result.PageIndex);
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        // Arrange
        var source = Enumerable.Empty<int>().AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 5);

        // Assert
        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(0, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void Create_SingleItem_OnePage()
    {
        // Arrange
        var source = new[] { 42 }.AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 5);

        // Assert
        Assert.AreEqual(1, result.Count);
        Assert.AreEqual(1, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }
}

