namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Create_FirstPage_ReturnsCorrectItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 5);

        // Assert
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(5, result[4]);
    }

    [TestMethod]
    public void Create_SecondPage_SkipsFirstPageItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 2, pageSize: 5);

        // Assert
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(6, result[0]);
        Assert.AreEqual(10, result[4]);
    }

    [TestMethod]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 12).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 3, pageSize: 5);

        // Assert
        Assert.AreEqual(2, result.Count);
        Assert.AreEqual(11, result[0]);
        Assert.AreEqual(12, result[1]);
    }

    [TestMethod]
    public void TotalPages_CalculatedCorrectly()
    {
        // Arrange
        var source = Enumerable.Range(1, 12).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 5);

        // Assert
        Assert.AreEqual(3, result.TotalPages); // ceil(12/5) = 3
    }

    [TestMethod]
    public void TotalPages_ExactDivision_NoExtraPage()
    {
        // Arrange
        var source = Enumerable.Range(1, 10).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 5);

        // Assert
        Assert.AreEqual(2, result.TotalPages);
    }

    [TestMethod]
    public void HasPreviousPage_OnFirstPage_ReturnsFalse()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 5);

        // Assert
        Assert.IsFalse(result.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_OnSecondPage_ReturnsTrue()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 2, pageSize: 5);

        // Assert
        Assert.IsTrue(result.HasPreviousPage);
    }

    [TestMethod]
    public void HasNextPage_OnLastPage_ReturnsFalse()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 4, pageSize: 5);

        // Assert
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_OnFirstPage_ReturnsTrue()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 5);

        // Assert
        Assert.IsTrue(result.HasNextPage);
    }

    [TestMethod]
    public void PageIndex_StoresCorrectValue()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 3, pageSize: 5);

        // Assert
        Assert.AreEqual(3, result.PageIndex);
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        // Arrange
        var source = Enumerable.Empty<int>().AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 5);

        // Assert
        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(0, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void Create_SingleItem_OnePage()
    {
        // Arrange
        var source = new[] { 42 }.AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 5);

        // Assert
        Assert.AreEqual(1, result.Count);
        Assert.AreEqual(1, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }
}

