using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class StudentsControllerTests
{
    private SchoolContext _context = null!;
    private StudentsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.CreateSeeded();
        _controller = new StudentsController(_context);
        _controller.TempData = new TempDataDictionary(new DefaultHttpContext(), 
            new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [TestMethod]
    public void Index_NoParams_ReturnsViewWithStudentsOrderedByLastName()
    {
        // Act
        var result = _controller.Index(null, null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.IsTrue(model.Count > 0);
        // Default sort is by LastName ascending
        Assert.AreEqual("Alexander", model[0].LastName);
    }

    [TestMethod]
    public void Index_NameDescSort_ReturnsDescendingOrder()
    {
        // Act
        var result = _controller.Index("name_desc", null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        // Barzdukas should be first in descending order
        Assert.AreEqual("Barzdukas", model[0].LastName);
    }

    [TestMethod]
    public void Index_DateSort_ReturnsAscendingByDate()
    {
        // Act
        var result = _controller.Index("Date", null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        // 2010 enrollment should be first
        Assert.AreEqual("Alexander", model[0].LastName);
    }

    [TestMethod]
    public void Index_DateDescSort_ReturnsDescendingByDate()
    {
        // Act
        var result = _controller.Index("date_desc", null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        // 2013 enrollment should be first
        Assert.AreEqual("Anand", model[0].LastName);
    }

    [TestMethod]
    public void Index_WithSearchString_FiltersResults()
    {
        // Act
        var result = _controller.Index(null, null, "Alexander", null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Alexander", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchByFirstName_FiltersResults()
    {
        // Act
        var result = _controller.Index(null, null, "Meredith", null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Alonso", model[0].LastName);
    }

    [TestMethod]
    public void Index_NewSearchString_ResetsPageToOne()
    {
        // Act - when searchString is not null, page resets to 1
        var result = _controller.Index(null, null, "A", 3) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.PageIndex);
    }

    [TestMethod]
    public void Index_NullSearchString_UsesCurrentFilter()
    {
        // Act - null searchString preserves currentFilter
        var result = _controller.Index(null, "Alonso", null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
    }

    [TestMethod]
    public void Details_WithValidId_ReturnsStudent()
    {
        // Act
        var result = _controller.Details(10) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var student = result.Model as Student;
        Assert.IsNotNull(student);
        Assert.AreEqual("Alexander", student.LastName);
    }

    [TestMethod]
    public void Details_WithNullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Create_Get_ReturnsViewWithStudentHavingTodaysDate()
    {
        // Act
        var result = _controller.Create() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var student = result.Model as Student;
        Assert.IsNotNull(student);
        Assert.AreEqual(DateTime.Today, student.EnrollmentDate);
    }

    [TestMethod]
    public void Create_Post_ValidStudent_RedirectsToIndex()
    {
        // Arrange
        var student = new Student
        {
            LastName = "TestLast",
            FirstMidName = "TestFirst",
            EnrollmentDate = new DateTime(2024, 1, 15)
        };

        // Act
        var result = _controller.Create(student) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(1, _context.Students.Count(s => s.LastName == "TestLast"));
    }

    [TestMethod]
    public void Create_Post_InvalidEnrollmentDate_ReturnsViewWithError()
    {
        // Arrange
        var student = new Student
        {
            LastName = "TestLast",
            FirstMidName = "TestFirst",
            EnrollmentDate = DateTime.MinValue
        };

        // Act
        var result = _controller.Create(student) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsFalse(_controller.ModelState.IsValid);
        Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [TestMethod]
    public void Create_Post_DateBefore1753_ReturnsViewWithError()
    {
        // Arrange
        var student = new Student
        {
            LastName = "TestLast",
            FirstMidName = "TestFirst",
            EnrollmentDate = new DateTime(1752, 12, 31)
        };

        // Act
        var result = _controller.Create(student) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [TestMethod]
    public void Edit_Get_WithValidId_ReturnsStudentView()
    {
        // Act
        var result = _controller.Edit(10) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var student = result.Model as Student;
        Assert.IsNotNull(student);
        Assert.AreEqual("Alexander", student.LastName);
    }

    [TestMethod]
    public void Edit_Get_WithNullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Edit(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Edit_Get_WithInvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Edit(9999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Edit_Post_ValidStudent_RedirectsToIndex()
    {
        // Arrange
        var student = _context.Students.Find(10)!;
        _context.Entry(student).State = EntityState.Detached;

        var updated = new Student
        {
            ID = 10,
            LastName = "UpdatedLast",
            FirstMidName = "UpdatedFirst",
            EnrollmentDate = new DateTime(2024, 6, 1)
        };

        // Act
        var result = _controller.Edit(updated) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Edit_Post_InvalidEnrollmentDate_ReturnsViewWithError()
    {
        // Arrange
        var student = new Student
        {
            ID = 10,
            LastName = "Test",
            FirstMidName = "Student",
            EnrollmentDate = DateTime.MinValue
        };

        // Act
        var result = _controller.Edit(student) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [TestMethod]
    public void Delete_Get_WithValidId_ReturnsStudentView()
    {
        // Act
        var result = _controller.Delete(10) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var student = result.Model as Student;
        Assert.IsNotNull(student);
        Assert.AreEqual("Alexander", student.LastName);
    }

    [TestMethod]
    public void Delete_Get_WithNullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Delete(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Delete_Get_WithInvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Delete(9999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void DeleteConfirmed_RemovesStudentAndRedirects()
    {
        // Arrange
        var countBefore = _context.Students.Count();

        // Act
        var result = _controller.DeleteConfirmed(10) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(countBefore - 1, _context.Students.Count());
    }
}

