    public void Setup()
    {
        _context = TestDbContextFactory.CreateSeeded();
        _controller = new NotificationsController(_context);
        _controller.TempData = new TempDataDictionary(new DefaultHttpContext(),
            new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));

        // Drain any leftover notifications
        _notificationService = new NotificationService();
        while (_notificationService.ReceiveNotification() != null) { }
    }

