using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using Moq;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class CoursesControllerTests
{
    private SchoolContext _context = null!;
    private CoursesController _controller = null!;
    private Mock<IWebHostEnvironment> _envMock = null!;
    private Mock<ILogger<CoursesController>> _loggerMock = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.CreateSeeded();
        _envMock = new Mock<IWebHostEnvironment>();
        _envMock.Setup(e => e.WebRootPath).Returns(Path.GetTempPath());
        _envMock.Setup(e => e.ContentRootPath).Returns(Path.GetTempPath());
        _loggerMock = new Mock<ILogger<CoursesController>>();
        _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
        _controller.TempData = new TempDataDictionary(new DefaultHttpContext(),
            new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [TestMethod]
    public void Index_ReturnsViewWithAllCourses()
    {
        // Act
        var result = _controller.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<Course>;
        Assert.IsNotNull(model);
        Assert.AreEqual(3, model.Count);
    }

    [TestMethod]
    public void Details_WithValidId_ReturnsCourse()
    {
        // Act
        var result = _controller.Details(1050) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var course = result.Model as Course;
        Assert.IsNotNull(course);
        Assert.AreEqual("Chemistry", course.Title);
    }

    [TestMethod]
    public void Details_WithNullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Create_Get_ReturnsView()
    {
        // Act
        var result = _controller.Create() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsNotNull(result.Model);
    }

    [TestMethod]
    public void Create_Post_ValidCourse_RedirectsToIndex()
    {
        // Arrange
        var course = new Course
        {
            CourseID = 9999,
            Title = "New Course",
            Credits = 4,
            DepartmentID = 1
        };

        // Act
        var result = _controller.Create(course, null!) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.IsNotNull(_context.Courses.Find(9999));
    }

    [TestMethod]
    public void Create_Post_InvalidModel_ReturnsView()
    {
        // Arrange
        _controller.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 8888 };

        // Act
        var result = _controller.Create(course, null!) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Create_Post_WithInvalidFileExtension_ReturnsViewWithError()
    {
        // Arrange
        var course = new Course { CourseID = 7777, Title = "Test", Credits = 3, DepartmentID = 1 };
        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("test.exe");
        fileMock.Setup(f => f.Length).Returns(1024);

        // Act
        var result = _controller.Create(course, fileMock.Object) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [TestMethod]
    public void Create_Post_WithOversizedFile_ReturnsViewWithError()
    {
        // Arrange
        var course = new Course { CourseID = 7777, Title = "Test", Credits = 3, DepartmentID = 1 };
        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("test.jpg");
        fileMock.Setup(f => f.Length).Returns(6 * 1024 * 1024); // 6MB

        // Act
        var result = _controller.Create(course, fileMock.Object) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [TestMethod]
    public void Edit_Get_WithValidId_ReturnsCourseView()
    {
        // Act
        var result = _controller.Edit(1050) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var course = result.Model as Course;
        Assert.IsNotNull(course);
        Assert.AreEqual("Chemistry", course.Title);
    }

    [TestMethod]
    public void Edit_Get_WithNullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Edit(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Edit_Get_WithInvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Edit(9999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Edit_Post_ValidCourse_RedirectsToIndex()
    {
        // Arrange
        var existing = _context.Courses.Find(1050)!;
        _context.Entry(existing).State = EntityState.Detached;

        var course = new Course
        {
            CourseID = 1050,
            Title = "Updated Chemistry",
            Credits = 4,
            DepartmentID = 3
        };

        // Act
        var result = _controller.Edit(course, null!) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Edit_Post_InvalidModel_ReturnsView()
    {
        // Arrange
        _controller.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 1050 };

        // Act
        var result = _controller.Edit(course, null!) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Edit_Post_WithInvalidFileExtension_ReturnsViewWithError()
    {
        // Arrange
        var existing = _context.Courses.Find(1050)!;
        _context.Entry(existing).State = EntityState.Detached;

        var course = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 3 };
        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("test.txt");
        fileMock.Setup(f => f.Length).Returns(1024);

        // Act
        var result = _controller.Edit(course, fileMock.Object) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [TestMethod]
    public void Delete_Get_WithValidId_ReturnsCourseView()
    {
        // Act
        var result = _controller.Delete(1050) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var course = result.Model as Course;
        Assert.IsNotNull(course);
        Assert.AreEqual("Chemistry", course.Title);
    }

    [TestMethod]
    public void Delete_Get_WithNullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Delete(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void DeleteConfirmed_RemovesCourseAndRedirects()
    {
        // Arrange
        var countBefore = _context.Courses.Count();

        // Act
        var result = _controller.DeleteConfirmed(1050) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(countBefore - 1, _context.Courses.Count());
    }
}

