using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class DepartmentsControllerTests
{
    private SchoolContext _context = null!;
    private DepartmentsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.CreateSeeded();
        _controller = new DepartmentsController(_context);
        _controller.TempData = new TempDataDictionary(new DefaultHttpContext(),
            new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [TestMethod]
    public void Index_ReturnsViewWithAllDepartments()
    {
        // Act
        var result = _controller.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<Department>;
        Assert.IsNotNull(model);
        Assert.AreEqual(3, model.Count);
    }

    [TestMethod]
    public void Details_WithValidId_ReturnsDepartment()
    {
        // Act
        var result = _controller.Details(1) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var department = result.Model as Department;
        Assert.IsNotNull(department);
        Assert.AreEqual("English", department.Name);
    }

    [TestMethod]
    public void Details_WithNullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Details_WithInvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Details(9999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Create_Get_ReturnsView()
    {
        // Act
        var result = _controller.Create() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Create_Post_ValidDepartment_RedirectsToIndex()
    {
        // Arrange
        var department = new Department
        {
            Name = "Physics",
            Budget = 200000,
            StartDate = new DateTime(2024, 1, 1),
            InstructorID = 1
        };

        // Act
        var result = _controller.Create(department) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(4, _context.Departments.Count());
    }

    [TestMethod]
    public void Create_Post_InvalidModel_ReturnsView()
    {
        // Arrange
        _controller.ModelState.AddModelError("Name", "Required");
        var department = new Department();

        // Act
        var result = _controller.Create(department) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Edit_Get_WithValidId_ReturnsDepartmentView()
    {
        // Act
        var result = _controller.Edit(1) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var department = result.Model as Department;
        Assert.IsNotNull(department);
        Assert.AreEqual("English", department.Name);
    }

    [TestMethod]
    public void Edit_Get_WithNullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Edit(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Edit_Get_WithInvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Edit(9999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Edit_Post_ValidDepartment_RedirectsToIndex()
    {
        // Arrange
        var existing = _context.Departments.Find(1)!;
        _context.Entry(existing).State = EntityState.Detached;

        var department = new Department
        {
            DepartmentID = 1,
            Name = "Updated English",
            Budget = 400000,
            StartDate = new DateTime(2007, 9, 1),
            InstructorID = 1
        };

        // Act
        var result = _controller.Edit(department) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Edit_Post_InvalidModel_ReturnsView()
    {
        // Arrange
        _controller.ModelState.AddModelError("Name", "Required");
        var department = new Department { DepartmentID = 1 };

        // Act
        var result = _controller.Edit(department) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Delete_Get_WithValidId_ReturnsDepartmentView()
    {
        // Act
        var result = _controller.Delete(1) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var department = result.Model as Department;
        Assert.IsNotNull(department);
        Assert.AreEqual("English", department.Name);
    }

    [TestMethod]
    public void Delete_Get_WithNullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Delete(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Delete_Get_WithInvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Delete(9999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void DeleteConfirmed_RemovesDepartmentAndRedirects()
    {
        // Arrange
        var countBefore = _context.Departments.Count();

        // Act
        var result = _controller.DeleteConfirmed(1) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(countBefore - 1, _context.Departments.Count());
    }
}

