using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class InstructorsControllerTests
{
    private SchoolContext _context = null!;
    private InstructorsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.CreateSeeded();

        // Add course assignments for testing
        _context.CourseAssignments.AddRange(
            new CourseAssignment { InstructorID = 1, CourseID = 1050 },
            new CourseAssignment { InstructorID = 1, CourseID = 4022 }
        );
        _context.SaveChanges();

        _controller = new InstructorsController(_context);
        _controller.TempData = new TempDataDictionary(new DefaultHttpContext(),
            new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [TestMethod]
    public void Index_NoParams_ReturnsViewWithInstructors()
    {
        // Act
        var result = _controller.Index(null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Models.SchoolViewModels.InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.AreEqual(3, model.Instructors.Count());
    }

    [TestMethod]
    public void Index_WithInstructorId_PopulatesCourses()
    {
        // Act
        var result = _controller.Index(1, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Models.SchoolViewModels.InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.Courses);
        Assert.AreEqual(2, model.Courses.Count());
    }

    [TestMethod]
    public void Index_WithInstructorAndCourseId_PopulatesEnrollments()
    {
        // Add enrollments for the course
        _context.Enrollments.Add(new Enrollment { CourseID = 1050, StudentID = 10, Grade = Grade.A });
        _context.SaveChanges();

        // Act
        var result = _controller.Index(1, 1050) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Models.SchoolViewModels.InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.Enrollments);
    }

    [TestMethod]
    public void Details_WithValidId_ReturnsInstructor()
    {
        // Act
        var result = _controller.Details(1) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var instructor = result.Model as Instructor;
        Assert.IsNotNull(instructor);
        Assert.AreEqual("Abercrombie", instructor.LastName);
    }

    [TestMethod]
    public void Details_WithNullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Details_WithInvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Details(9999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Create_Get_ReturnsViewWithInstructor()
    {
        // Act
        var result = _controller.Create() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var instructor = result.Model as Instructor;
        Assert.IsNotNull(instructor);
        Assert.IsNotNull(instructor.CourseAssignments);
    }

    [TestMethod]
    public void Create_Post_ValidInstructor_RedirectsToIndex()
    {
        // Arrange
        var instructor = new Instructor
        {
            LastName = "NewInstructor",
            FirstMidName = "Test",
            HireDate = new DateTime(2024, 1, 1)
        };

        // Act
        var result = _controller.Create(instructor, null!) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Create_Post_WithSelectedCourses_AddsCourseAssignments()
    {
        // Arrange
        var instructor = new Instructor
        {
            LastName = "CourseInstructor",
            FirstMidName = "New",
            HireDate = new DateTime(2024, 1, 1)
        };
        var selectedCourses = new[] { "1050", "4022" };

        // Act
        var result = _controller.Create(instructor, selectedCourses) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        var saved = _context.Instructors
            .Include(i => i.CourseAssignments)
            .First(i => i.LastName == "CourseInstructor");
        Assert.AreEqual(2, saved.CourseAssignments.Count);
    }

    [TestMethod]
    public void Create_Post_InvalidModel_ReturnsView()
    {
        // Arrange
        _controller.ModelState.AddModelError("LastName", "Required");
        var instructor = new Instructor
        {
            CourseAssignments = new List<CourseAssignment>()
        };

        // Act
        var result = _controller.Create(instructor, null!) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Delete_Get_WithValidId_ReturnsInstructorView()
    {
        // Act
        var result = _controller.Delete(1) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var instructor = result.Model as Instructor;
        Assert.IsNotNull(instructor);
        Assert.AreEqual("Abercrombie", instructor.LastName);
    }

    [TestMethod]
    public void Delete_Get_WithNullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Delete(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Delete_Get_WithInvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Delete(9999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void DeleteConfirmed_RemovesInstructorAndRedirects()
    {
        // Arrange - Add office assignment to test full deletion
        _context.OfficeAssignments.Add(new OfficeAssignment { InstructorID = 2, Location = "Office 101" });
        _context.SaveChanges();

        var countBefore = _context.Instructors.Count();

        // Act
        var result = _controller.DeleteConfirmed(2) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(countBefore - 1, _context.Instructors.Count());
    }

    [TestMethod]
    public void DeleteConfirmed_NullsDepartmentAdministrator()
    {
        // The department with ID=1 has InstructorID=1 as administrator
        // Act
        _controller.DeleteConfirmed(1);

        // Assert
        var dept = _context.Departments.Find(1);
        Assert.IsNotNull(dept);
        Assert.IsNull(dept.InstructorID);
    }
}

