using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class NotificationsControllerTests
{
    private SchoolContext _context = null!;
    private NotificationsController _controller = null!;
    private NotificationService _notificationService = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.CreateSeeded();
        _controller = new NotificationsController(_context);
        _controller.TempData = new TempDataDictionary(new DefaultHttpContext(),
            new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));

        // Drain any leftover notifications
        _notificationService = new NotificationService();
        while (_notificationService.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller.Dispose();
        _context.Dispose();
        _notificationService.Dispose();
    }

    [TestMethod]
    public void GetNotifications_WhenEmpty_ReturnsSuccessWithEmptyList()
    {
        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var json = result.Value;
        Assert.IsNotNull(json);

        // Use dynamic to access anonymous type properties
        var successProp = json.GetType().GetProperty("success");
        var countProp = json.GetType().GetProperty("count");
        Assert.IsNotNull(successProp);
        Assert.IsNotNull(countProp);
        Assert.AreEqual(true, successProp.GetValue(json));
        Assert.AreEqual(0, countProp.GetValue(json));
    }

    [TestMethod]
    public void GetNotifications_WithNotifications_ReturnsThemAndDrainsQueue()
    {
        // Arrange
        _notificationService.SendNotification("Student", "1", "Test", EntityOperation.CREATE);
        _notificationService.SendNotification("Course", "2", "Math", EntityOperation.UPDATE);

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var json = result.Value;
        Assert.IsNotNull(json);
        var countProp = json.GetType().GetProperty("count");
        Assert.IsNotNull(countProp);
        Assert.AreEqual(2, countProp.GetValue(json));
    }

    [TestMethod]
    public void GetNotifications_LimitsTo10()
    {
        // Arrange - Add 15 notifications
        for (int i = 0; i < 15; i++)
        {
            _notificationService.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
        }

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var json = result.Value;
        Assert.IsNotNull(json);
        var countProp = json.GetType().GetProperty("count");
        Assert.IsNotNull(countProp);
        Assert.AreEqual(10, countProp.GetValue(json));
    }

    [TestMethod]
    public void MarkAsRead_ReturnsSuccess()
    {
        // Act
        var result = _controller.MarkAsRead(1);

        // Assert
        Assert.IsNotNull(result);
        var json = result.Value;
        Assert.IsNotNull(json);
        var successProp = json.GetType().GetProperty("success");
        Assert.IsNotNull(successProp);
        Assert.AreEqual(true, successProp.GetValue(json));
    }

    [TestMethod]
    public void Index_ReturnsView()
    {
        // Act
        var result = _controller.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }
}

