using ContosoUniversity.Models;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PersonModelTests
{
    [TestMethod]
    public void FullName_ReturnsLastNameCommaFirstName()
    {
        // Arrange
        var student = new Student
        {
            LastName = "Smith",
            FirstMidName = "John"
        };

        // Assert
        Assert.AreEqual("Smith, John", student.FullName);
    }

    [TestMethod]
    [DataRow("Doe", "Jane", "Doe, Jane")]
    [DataRow("O'Brien", "Alice", "O'Brien, Alice")]
    [DataRow("", "Test", ", Test")]
    public void FullName_FormatsCorrectly(string lastName, string firstName, string expected)
    {
        // Arrange
        var instructor = new Instructor
        {
            LastName = lastName,
            FirstMidName = firstName,
            HireDate = DateTime.Now
        };

        // Assert
        Assert.AreEqual(expected, instructor.FullName);
    }
}

