public void GetNotifications_WithNotifications_ReturnsThemAndDrainsQueue()
{
    // Arrange
    _notificationService.SendNotification("Student", "1", "Test", EntityOperation.CREATE);
    _notificationService.SendNotification("Course", "2", "Math", EntityOperation.UPDATE);

    // Act
    var result = _controller.GetNotifications();

    // Assert
    Assert.IsNotNull(result);
    var json = result.Value;
    Assert.IsNotNull(json);
    var countProp = json.GetType().GetProperty("count");
    Assert.IsNotNull(countProp);
    var count = (int)countProp.GetValue(json)!;
    Assert.IsTrue(count >= 2, $"Expected at least 2 notifications, got {count}");
}

